async function i(){try{window.supabaseAuthReady&&await window.supabaseAuthReady;const e=await window.getCurrentUser();if(!e.success||!e.user)return console.log("❌ Usuario no autenticado, redirigiendo a signin..."),window.location.href="./signin.html",null;const n=e.user,o=await window.getBusinessInfo(n.id);return!o.success||!o.data?(console.log("⚠️ Usuario sin información de negocio, redirigiendo a complete-profile..."),window.location.href="./complete-profile.html",null):(console.log("✅ Usuario con acceso completo verificado"),{user:n,businessInfo:o.data})}catch(e){return console.error("❌ Error al verificar acceso:",e),window.location.href="./signin.html",null}}async function s(){try{const e=await window.getCurrentUser();return!e.success||!e.user?(console.log("❌ Usuario no autenticado, redirigiendo a signin..."),window.location.href="./signin.html",null):(console.log("✅ Usuario autenticado verificado"),e.user)}catch(e){return console.error("❌ Error al verificar autenticación:",e),window.location.href="./signin.html",null}}window.checkBusinessInfoComplete=i;window.checkAuthOnly=s;console.log("✅ CheckBusinessInfo module loaded successfully");
